const event = $('Execute Workflow Trigger').item.json;
const pgRow = $('Fetch Budget Data').item.json || {};
const safeArr = v => Array.isArray(v) ? v : [];
const safeObj = v => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};

const contribBack = safeArr($('GitHub Contributors Backend').item.json);
const contribFront = safeArr($('GitHub Contributors Frontend').item.json);
const kpis = safeObj(pgRow.kpis);
const fases = safeObj(pgRow.fases);
const ranking = safeArr(pgRow.ranking);
const teamRates = safeArr(pgRow.team_rates);
const lastSnap = safeObj(pgRow.last_snapshot);
const progreso = Number(pgRow.progreso_pct || 0);

// --- PROJECT BUDGET CONSTANTS ---
const BUDGET_TOTAL = 2758.00;
const BUDGET_RRHH = 2368.00;
const BUDGET_INFRA = 140.00;
const BUDGET_INDIRECTOS = 250.00;
const PROJECT_START = new Date('2026-02-03');
const PROJECT_END = new Date('2026-06-10');
const TOTAL_WEEKS = 16;
const VPS_MONTHLY = 15.00; // Contabo estimated
const now = new Date();

// Weeks elapsed
const msElapsed = now - PROJECT_START;
const weeksElapsed = Math.max(1, Math.round(msElapsed / (7 * 86400000)));
const weeksRemaining = Math.max(0, TOTAL_WEEKS - weeksElapsed);

// --- RRHH COST CALCULATION (dynamic from team rates + Trello activity) ---
const rateMap = {};
for (const r of teamRates) { rateMap[String(r.miembro).toLowerCase()] = r; }

// Estimate hours worked per member from Trello ranking (tasks done = proxy for work)
let gastadoRRHH = 0;
const memberCosts = [];
const plannedWeeklyRRHH = teamRates.reduce((s, r) => s + (r.tarifa_hora * r.horas_semana), 0);

for (const r of teamRates) {
  const weeklyRate = r.tarifa_hora * r.horas_semana;
  const totalPlanned = weeklyRate * TOTAL_WEEKS;
  const spent = weeklyRate * weeksElapsed;
  gastadoRRHH += spent;
  memberCosts.push({
    nombre: r.miembro,
    rol: r.rol,
    tarifa: r.tarifa_hora,
    horas_sem: r.horas_semana,
    gasto_acum: Number(spent.toFixed(2)),
    presupuesto: Number(totalPlanned.toFixed(2)),
    pct_usado: Number(((spent / totalPlanned) * 100).toFixed(1))
  });
}

// --- INFRA COST ---
const monthsElapsed = Math.max(1, Math.ceil(msElapsed / (30 * 86400000)));
const gastadoInfra = 80 + (VPS_MONTHLY * monthsElapsed); // Hardware=80 one-time + VPS monthly

// --- INDIRECTOS ---
const gastadoIndirectos = (BUDGET_INDIRECTOS / TOTAL_WEEKS) * weeksElapsed;

const gastadoTotal = Number((gastadoRRHH + gastadoInfra + gastadoIndirectos).toFixed(2));
const burnRateSemanal = Number((gastadoTotal / weeksElapsed).toFixed(2));
const pctPresupuestoUsado = Number(((gastadoTotal / BUDGET_TOTAL) * 100).toFixed(2));

// --- EARNED VALUE MANAGEMENT ---
const pctPlanificado = Number(((weeksElapsed / TOTAL_WEEKS) * 100).toFixed(2));
const BAC = BUDGET_TOTAL;
const PV = BAC * (pctPlanificado / 100);
const EV = BAC * (progreso / 100);
const AC = gastadoTotal;
const CPI = AC > 0 ? Number((EV / AC).toFixed(2)) : 1;
const SPI = PV > 0 ? Number((EV / PV).toFixed(2)) : 1;
const EAC = CPI > 0 ? Number((BAC / CPI).toFixed(2)) : BAC * 2;
const ETC = Math.max(0, Number((EAC - AC).toFixed(2)));
const VAC = Number((BAC - EAC).toFixed(2));
const burnProjected = burnRateSemanal * weeksRemaining + gastadoTotal;

// Semáforo
let semaforo = 'verde';
if (CPI < 0.85 || SPI < 0.8 || pctPresupuestoUsado > 90) semaforo = 'rojo';
else if (CPI < 0.95 || SPI < 0.9 || pctPresupuestoUsado > 75) semaforo = 'amarillo';

// --- GitHub activity cost attribution ---
const ghNameMap = { 'davidmanjarres': 'Manjarres David', 'barragandavid': 'Barragán David', 'josuegarciaabata': 'García Josué', 'bonillajoel': 'Bonilla Joel' };
const commitsByAuthor = {};
for (const c of [...contribBack, ...contribFront]) {
  const login = String(c.author?.login || '').toLowerCase();
  const total = c.total || 0;
  commitsByAuthor[login] = (commitsByAuthor[login] || 0) + total;
}

const memberDetails = memberCosts.map(m => {
  const loginKey = Object.keys(ghNameMap).find(k => ghNameMap[k] === m.nombre) || '';
  const commits = commitsByAuthor[loginKey] || 0;
  return `${m.nombre} (${m.rol}): $${m.gasto_acum}/$${m.presupuesto} (${m.pct_usado}%) · ${commits} commits`;
}).join('\n');

const prompt = `Eres el FinOps Controller del proyecto PetSafe (sistema veterinario, NestJS+Angular, cierre 10-jun-2026). Analiza los datos financieros y genera un diagnóstico de presupuesto y burn rate. Texto plano, SIN markdown, SIN asteriscos, en español.\n\nPRESUPUESTO APROBADO\nTotal: $${BUDGET_TOTAL} | RRHH: $${BUDGET_RRHH} | Infra: $${BUDGET_INFRA} | Indirectos: $${BUDGET_INDIRECTOS}\n\nEJECUCION ACTUAL (semana ${weeksElapsed}/${TOTAL_WEEKS})\nGastado total: $${gastadoTotal} de $${BUDGET_TOTAL} (${pctPresupuestoUsado}%)\nRRHH: $${gastadoRRHH.toFixed(2)} | Infra: $${gastadoInfra.toFixed(2)} | Indirectos: $${gastadoIndirectos.toFixed(2)}\nBurn rate semanal: $${burnRateSemanal}/semana\nProyeccion al cierre: $${burnProjected.toFixed(2)}\n\nEARNED VALUE\nCPI: ${CPI} (${CPI >= 1 ? 'eficiente' : 'ineficiente, gastando mas de lo que produce'})\nSPI: ${SPI} (${SPI >= 1 ? 'a tiempo o adelantado' : 'retrasado respecto al plan'})\nEAC (costo estimado final): $${EAC}\nVAC (variacion al cierre): $${VAC} (${VAC >= 0 ? 'bajo presupuesto' : 'sobre presupuesto'})\nETC (costo para terminar): $${ETC}\nSemaforo: ${semaforo.toUpperCase()}\n\nAvance real del proyecto: ${progreso}% | Avance planificado: ${pctPlanificado}%\nSemanas restantes: ${weeksRemaining}\n\nDETALLE POR MIEMBRO:\n${memberDetails}\n\nSecciones obligatorias (max 3 oraciones cada una):\nRESUMEN FINANCIERO: Estado general del presupuesto en una oracion.\nBURN RATE: Si el ritmo actual es sostenible o requiere ajuste.\nEARNED VALUE: Interpretacion del CPI y SPI para el negocio.\nRIESGOS FINANCIEROS: Top 2 riesgos de costo o eficiencia.\nRECOMENDACIONES: 2 acciones concretas para optimizar el gasto.`;

return [{ json: {
  correlation_id: event.correlation_id || `finops-${Date.now()}`,
  event_type: event.event_type || 'finops_report',
  prompt,
  metrics: { presupuesto_total: BUDGET_TOTAL, gastado_rrhh: gastadoRRHH, gastado_infra: gastadoInfra, gastado_indirectos: gastadoIndirectos, gastado_total: gastadoTotal, burn_rate_semanal: burnRateSemanal, semanas_transcurridas: weeksElapsed, semanas_restantes: weeksRemaining, pct_presupuesto_usado: pctPresupuestoUsado, pct_proyecto_completado: progreso, cpi: CPI, spi: SPI, eac: EAC, etc: ETC, vac: VAC, semaforo, burn_projected: burnProjected, member_costs: memberCosts },
  semaforo, gastadoTotal, CPI, SPI, EAC, pctPresupuestoUsado, burnRateSemanal, progreso, weeksElapsed, weeksRemaining, BUDGET_TOTAL, memberDetails
}}];

const raw = $json.text ?? $json.output ?? $json.response ?? '';
const iaText = typeof raw === 'string' ? raw.trim() : JSON.stringify(raw);
const ctx = $('Build FinOps Context').item.json;
const m = ctx.metrics;
const semE = { verde: '🟢', amarillo: '🟡', rojo: '🔴' }[ctx.semaforo] || '⚪';
const colorMap = { rojo: 15158332, amarillo: 16761095, verde: 3066993 };
const cpiE = ctx.CPI >= 1 ? '✅' : ctx.CPI >= 0.9 ? '⚠️' : '❌';
const spiE = ctx.SPI >= 1 ? '✅' : ctx.SPI >= 0.9 ? '⚠️' : '❌';
const discord_payload = {
  username: 'PM PetSafe · FinOps',
  embeds: [{
    title: `${semE} Reporte Financiero PetSafe · Semana ${ctx.weeksElapsed}/${ctx.weeksElapsed + ctx.weeksRemaining}`,
    description: `Presupuesto: **$${ctx.BUDGET_TOTAL}** · Gastado: **$${ctx.gastadoTotal}** (${ctx.pctPresupuestoUsado}%)`,
    color: colorMap[ctx.semaforo] || 3066993,
    fields: [
      { name: '🔥 Burn Rate', value: `**$${ctx.burnRateSemanal}**/semana · Proyección: $${m.burn_projected?.toFixed(2)}`, inline: true },
      { name: '📊 Earned Value', value: `${cpiE} CPI: **${ctx.CPI}** · ${spiE} SPI: **${ctx.SPI}**`, inline: true },
      { name: '🎯 EAC/VAC', value: `Costo estimado final: **$${ctx.EAC}** · Variación: **$${m.vac}**`, inline: false },
      { name: '👥 Costo por Miembro', value: ctx.memberDetails.slice(0, 900), inline: false },
      { name: '🤖 Diagnóstico FinOps', value: iaText.slice(0, 900), inline: false }
    ],
    footer: { text: 'FinOps Budget Tracker · PM PetSafe AI' },
    timestamp: new Date().toISOString()
  }]
};
return [{ json: {
  correlation_id: ctx.correlation_id, agent_role: 'FinOps Budget Tracker', decision_type: 'finops_report',
  input_summary: `FinOps: $${ctx.gastadoTotal}/$${ctx.BUDGET_TOTAL} (${ctx.pctPresupuestoUsado}%), CPI=${ctx.CPI}`.slice(0,500),
  context_used: { gastado: ctx.gastadoTotal, cpi: ctx.CPI, spi: ctx.SPI },
  evidence: { metrics: m, ia: iaText.slice(0,1000) },
  decision: { semaforo: ctx.semaforo, eac: ctx.EAC }, recommendation: iaText.slice(0,500),
  confidence: 0.9, risk_level: ctx.semaforo === 'rojo' ? 'high' : ctx.semaforo === 'amarillo' ? 'medium' : 'low',
  requires_human_approval: ctx.semaforo === 'rojo', discord_payload, metrics: m, ia_text: iaText
}}];
